import{_ as i,c as e,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"プラットフォーム機能: モデルとクォータ | opencode-antigravity-auth","description":"Antigravity Auth のモデルタイプとデュアルクォータシステムについて学習します。モデル選択、Thinking 設定、Google Search の方法を習得し、クォータを最適化して活用します。","frontmatter":{"title":"プラットフォーム機能: モデルとクォータ | opencode-antigravity-auth","sidebarTitle":"デュアルクォータシステムの活用","subtitle":"プラットフォーム機能: モデルとクォータ","description":"Antigravity Auth のモデルタイプとデュアルクォータシステムについて学習します。モデル選択、Thinking 設定、Google Search の方法を習得し、クォータを最適化して活用します。","order":2},"headers":[],"relativePath":"ja/NoeFabris/opencode-antigravity-auth/platforms/index.md","filePath":"ja/NoeFabris/opencode-antigravity-auth/platforms/index.md"}'),o={name:"ja/NoeFabris/opencode-antigravity-auth/platforms/index.md"};function n(r,a,h,d,s,u){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="プラットフォーム機能" tabindex="-1">プラットフォーム機能 <a class="header-anchor" href="#プラットフォーム機能" aria-label="Permalink to &quot;プラットフォーム機能&quot;">​</a></h1><p>この章では、Antigravity Auth プラグインがサポートするモデル、クォータシステム、プラットフォーム機能について詳しく説明します。適切なモデルを選択する方法、Thinking 能力の設定、Google Search の有効化、およびクォータ利用率の最大化を学びます。</p><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前の確認</p><p>この章を学習する前に、以下が完了していることを確認してください：</p><ul><li><a href="./../start/quick-install/">クイックインストール</a>：プラグインのインストールと初回認証を完了する</li><li><a href="./../start/first-request/">最初のリクエスト</a>：最初のモデルリクエストを正常に送信する</li></ul></div><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><p>以下の順序で学習してください。プラットフォーム機能を段階的に習得できます：</p><h3 id="_1-利用可能なモデル" tabindex="-1">1. <a href="./available-models/">利用可能なモデル</a> <a class="header-anchor" href="#_1-利用可能なモデル" aria-label="Permalink to &quot;1. [利用可能なモデル](./available-models/)&quot;">​</a></h3><p>利用可能なモデルとそのバリアント設定について学びます。</p><ul><li>Claude Opus 4.5、Sonnet 4.5、Gemini 3 Pro/Flash の種類と特徴</li><li>Antigravity および Gemini CLI クォータプールのモデル分布</li><li>バリアント選択とモデルの最適活用方法</li><li><code>--variant</code> パラメータの活用法</li></ul><h3 id="_2-デュアルクォータシステム" tabindex="-1">2. <a href="./dual-quota-system/">デュアルクォータシステム</a> <a class="header-anchor" href="#_2-デュアルクォータシステム" aria-label="Permalink to &quot;2. [デュアルクォータシステム](./dual-quota-system/)&quot;">​</a></h3><p>Antigravity と Gemini CLI のデュアルクォータプールの仕組みを理解します。</p><ul><li>各アカウントが持つ独立した Gemini クォータプールの仕組み</li><li>自動 fallback 設定によるクォータ効率的利用</li><li>特定モデルのクォータプール明示的選択</li></ul><h3 id="_3-google-search-grounding" tabindex="-1">3. <a href="./google-search-grounding/">Google Search Grounding</a> <a class="header-anchor" href="#_3-google-search-grounding" aria-label="Permalink to &quot;3. [Google Search Grounding](./google-search-grounding/)&quot;">​</a></h3><p>Gemini モデルで Google Search を有効にし、事実確認精度を向上させます。</p><ul><li>Gemini によるリアルタイム Web 検索機能</li><li>検索の適用頻度と範囲の微細調整</li><li>タスク固有の最適な検索戦略選択</li></ul><h3 id="_4-thinking-モデル" tabindex="-1">4. <a href="./thinking-models/">Thinking モデル</a> <a class="header-anchor" href="#_4-thinking-モデル" aria-label="Permalink to &quot;4. [Thinking モデル](./thinking-models/)&quot;">​</a></h3><p>Claude と Gemini 3 Thinking モデルの高度な設定方法を習得します。</p><ul><li>Claude の思考予算戦略的設定</li><li>Gemini 3 の思考レベル（minimal/low/medium/high）適切選択</li><li>インターリーブ思考プロセスの精密管理</li></ul><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>この章の学習を終えた後、以下の進化的学習パスで理解を深化できます：</p><ul><li><a href="./../advanced/multi-account-setup/">複数アカウント設定</a>：複数の Google アカウントを設定し、クォータプール化と負荷分散を実現</li><li><a href="./../advanced/account-selection-strategies/">アカウント選択戦略</a>：sticky、round-robin、hybrid の 3 つの戦略のベストプラクティスを習得</li><li><a href="./../advanced/configuration-guide/">設定ガイド</a>：すべての設定オプションを習得し、ニーズに合わせてプラグインの動作をカスタマイズ</li></ul>',21)])])}const m=i(o,[["render",n]]);export{g as __pageData,m as default};
